const express = require('express');
const multer = require('multer');
const fs = require('fs');
const xml2js = require('xml2js');

const app = express();

const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('file'), function (req, res) {
    const xml = fs.readFileSync(req.file.path, 'utf-8');
    
    xml2js.parseString(xml, {xmlns: true, explicitArray: false}, (err, result) => {
        if (err) {
            return res.status(500).send({message: 'Unable to parse XML'});
        }
        fs.unlinkSync(req.file.path);
        
        const configuration = result;
        // This forward the configuration object to another handler
        handleConfiguration(configuration);

        res.status(200).send({message: 'File uploaded successfully'});
    });
});

